export declare const BUBBLE_CSS = "\n.tmrg-bubble {\n  position: fixed;\n  z-index: 2147483641;\n  width: 260px;\n  max-height: min(380px, calc(100vh - 120px));\n  display: flex;\n  flex-direction: column;\n  background: #ffffff;\n  border: 1.5px solid #e5e7eb;\n  border-radius: 16px;\n  box-shadow: 0 8px 32px rgba(0,0,0,0.14), 0 2px 8px rgba(0,0,0,0.08);\n  padding: 14px 16px 12px;\n  pointer-events: auto;\n  transition: left 0.45s cubic-bezier(0.34, 1.56, 0.64, 1),\n              top  0.45s cubic-bezier(0.34, 1.56, 0.64, 1),\n              opacity 0.2s ease,\n              transform 0.2s ease;\n  transform-origin: bottom left;\n  opacity: 0;\n  transform: scale(0.85) translateY(8px);\n}\n.tmrg-bubble.visible {\n  opacity: 1;\n  transform: scale(1) translateY(0);\n}\n\n/* Tail */\n.tmrg-bubble::before {\n  content: '';\n  position: absolute;\n  bottom: 18px;\n  width: 0; height: 0;\n  border-style: solid;\n}\n.tmrg-bubble[data-side=\"right\"]::before {\n  left: -9px;\n  border-width: 7px 9px 7px 0;\n  border-color: transparent #e5e7eb transparent transparent;\n}\n.tmrg-bubble[data-side=\"right\"]::after {\n  content: '';\n  position: absolute;\n  bottom: 19.5px;\n  left: -7px;\n  width: 0; height: 0;\n  border-style: solid;\n  border-width: 5.5px 7px 5.5px 0;\n  border-color: transparent #ffffff transparent transparent;\n}\n.tmrg-bubble[data-side=\"left\"]::before {\n  right: -9px;\n  border-width: 7px 0 7px 9px;\n  border-color: transparent transparent transparent #e5e7eb;\n}\n.tmrg-bubble[data-side=\"left\"]::after {\n  content: '';\n  position: absolute;\n  bottom: 19.5px;\n  right: -7px;\n  width: 0; height: 0;\n  border-style: solid;\n  border-width: 5.5px 0 5.5px 7px;\n  border-color: transparent transparent transparent #ffffff;\n}\n\n/* Dismiss button */\n.tmrg-bubble-dismiss {\n  position: absolute;\n  top: 8px; right: 10px;\n  background: none; border: none;\n  cursor: pointer;\n  color: #9ca3af;\n  font-size: 16px;\n  line-height: 1;\n  padding: 2px 4px;\n  border-radius: 4px;\n  pointer-events: auto;\n  flex-shrink: 0;\n}\n.tmrg-bubble-dismiss:hover { color: #374151; background: #f3f4f6; }\n\n/* Scrollable text area */\n.tmrg-bubble-scroll {\n  flex: 1;\n  overflow-y: auto;\n  min-height: 0;\n  /* subtle scrollbar */\n  scrollbar-width: thin;\n  scrollbar-color: #e5e7eb transparent;\n}\n.tmrg-bubble-scroll::-webkit-scrollbar { width: 4px; }\n.tmrg-bubble-scroll::-webkit-scrollbar-track { background: transparent; }\n.tmrg-bubble-scroll::-webkit-scrollbar-thumb { background: #e5e7eb; border-radius: 2px; }\n\n/* Text */\n.tmrg-bubble-text {\n  font-size: 13.5px;\n  line-height: 1.55;\n  color: #1f2937;\n  margin: 0;\n  padding-right: 12px;\n  min-height: 20px;\n}\n.tmrg-bubble-text b { font-weight: 600; }\n.tmrg-bubble-text a { color: #ff6700; text-decoration: underline; }\n\n/* Typing dots */\n.tmrg-typing {\n  display: flex;\n  gap: 4px;\n  align-items: center;\n  height: 22px;\n}\n.tmrg-typing span {\n  width: 6px; height: 6px;\n  border-radius: 50%;\n  background: #d1d5db;\n  animation: tmrg-dot 1.1s ease-in-out infinite;\n}\n.tmrg-typing span:nth-child(2) { animation-delay: 0.18s; }\n.tmrg-typing span:nth-child(3) { animation-delay: 0.36s; }\n@keyframes tmrg-dot {\n  0%, 80%, 100% { transform: translateY(0); background: #d1d5db; }\n  40%            { transform: translateY(-5px); background: #ff6700; }\n}\n@media (prefers-reduced-motion: reduce) {\n  .tmrg-typing span { animation: none; }\n  .tmrg-bubble { transition: opacity 0.15s ease !important; }\n}\n\n/* Q&A input area */\n.tmrg-bubble-input-row {\n  display: flex;\n  gap: 6px;\n  margin-top: 10px;\n  align-items: flex-end;\n  flex-shrink: 0;\n}\n.tmrg-bubble-input {\n  flex: 1;\n  resize: none;\n  border: 1.5px solid #e5e7eb;\n  border-radius: 8px;\n  padding: 6px 8px;\n  font-size: 12.5px;\n  line-height: 1.4;\n  font-family: inherit;\n  color: #1f2937;\n  background: #f9fafb;\n  outline: none;\n  max-height: 80px;\n  overflow-y: auto;\n}\n.tmrg-bubble-input:focus { border-color: #ff6700; background: #fff; }\n.tmrg-bubble-send {\n  flex-shrink: 0;\n  width: 30px; height: 30px;\n  border-radius: 8px;\n  border: none;\n  background: #ff6700;\n  color: white;\n  cursor: pointer;\n  display: flex; align-items: center; justify-content: center;\n  font-size: 14px;\n  padding: 0;\n}\n.tmrg-bubble-send:disabled { background: #d1d5db; cursor: not-allowed; }\n.tmrg-bubble-send:hover:not(:disabled) { background: #e85d00; }\n\n/* Follow-up chips */\n.tmrg-followups {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 5px;\n  margin-top: 8px;\n  flex-shrink: 0;\n}\n.tmrg-chip {\n  font-size: 11.5px;\n  background: #fff7ed;\n  color: #c2410c;\n  border: 1px solid #fed7aa;\n  border-radius: 20px;\n  padding: 3px 10px;\n  cursor: pointer;\n  transition: background 0.15s;\n}\n.tmrg-chip:hover { background: #ffedd5; }\n";
